<?php
/**
 * bin/build-frontend-assets.php
 *
 * Regenerates `audit/manifest.json`'s `.frontend_assets` block from the
 * on-disk asset tree. Tracks CANONICAL source files only — the *-rtl
 * and *.min variants generated by `npm run build:rtl` / `build:min` are
 * derived artefacts, not inventory.
 *
 * Categories:
 *   - css.global    assets/css/*.css                (plugin-wide stylesheets)
 *   - css.admin     assets/css/admin/**.css         (per-admin-page split)
 *   - css.blocks    src/Blocks/<slug>/style.css     (per-block front-end)
 *   - js.global     assets/js/*.js                  (plugin-wide scripts)
 *   - js.blocks     src/Blocks/<slug>/view.js       (per-block frontend logic)
 *
 * Idempotent. Updates `manifest.summary.json.counts.frontend_css_files`
 * + `frontend_js_files` to keep `bin/build-readme.php`'s feature counts
 * truthful (even though readme.txt doesn't currently inline those two,
 * downstream tooling — and any future inline — reads them from the
 * summary).
 *
 * Usage:
 *     php bin/build-frontend-assets.php
 *     php bin/build-frontend-assets.php --dry-run
 *
 * Exit codes:
 *   0  ok (or no-op)
 *   1  missing manifest
 *   2  write failed
 */

declare( strict_types = 1 );

$root        = dirname( __DIR__ );
$dry_run     = in_array( '--dry-run', $argv, true );
$manifest_fp = $root . '/audit/manifest.json';
$summary_fp  = $root . '/audit/manifest.summary.json';

if ( ! is_readable( $manifest_fp ) ) {
	fwrite( STDERR, "ERROR: missing {$manifest_fp}\n" );
	exit( 1 );
}

$manifest = json_decode( (string) file_get_contents( $manifest_fp ), true );
if ( ! is_array( $manifest ) ) {
	fwrite( STDERR, "ERROR: malformed manifest.json\n" );
	exit( 1 );
}

/**
 * @param string $glob Pattern relative to $root.
 * @return list<string> Relative paths.
 */
$collect = static function ( string $pattern ) use ( $root ): array {
	$results = glob( $root . '/' . $pattern ) ?: array();
	$out     = array();
	foreach ( $results as $abs ) {
		$rel = ltrim( str_replace( $root, '', $abs ), '/' );
		if ( is_canonical( $rel ) ) {
			$out[] = $rel;
		}
	}
	sort( $out );
	return $out;
};

/**
 * Recursive descent for **.css patterns since PHP's glob() doesn't
 * support **. Walks one directory tree, filters by extension.
 *
 * @return list<string>
 */
$walk = static function ( string $abs_dir, string $ext ) use ( $root ): array {
	if ( ! is_dir( $abs_dir ) ) {
		return array();
	}
	$it  = new RecursiveIteratorIterator( new RecursiveDirectoryIterator( $abs_dir ) );
	$out = array();
	foreach ( $it as $file ) {
		if ( ! $file->isFile() || $file->getExtension() !== $ext ) {
			continue;
		}
		$rel = ltrim( str_replace( $root, '', (string) $file->getRealPath() ), '/' );
		if ( is_canonical( $rel ) ) {
			$out[] = $rel;
		}
	}
	sort( $out );
	return $out;
};

// CSS — canonical sources only.
$css_global = $collect( 'assets/css/*.css' );        // top-level (non-page-split) stylesheets
$css_admin  = $walk( $root . '/assets/css/admin', 'css' );
$css_blocks = $collect( 'src/Blocks/*/style.css' );

// JS — canonical sources only.
$js_global = $collect( 'assets/js/*.js' );
$js_blocks = array();
foreach ( glob( $root . '/src/Blocks/*' ) ?: array() as $block_dir ) {
	if ( ! is_dir( $block_dir ) ) {
		continue;
	}
	foreach ( array( 'view.js', 'index.js' ) as $name ) {
		$rel = ltrim( str_replace( $root, '', $block_dir . '/' . $name ), '/' );
		if ( file_exists( $block_dir . '/' . $name ) && is_canonical( $rel ) ) {
			$js_blocks[] = $rel;
		}
	}
}
sort( $js_blocks );

$manifest['frontend_assets'] = array(
	'css' => array(
		'global' => $css_global,
		'admin'  => $css_admin,
		'blocks' => $css_blocks,
	),
	'js'  => array(
		'global' => $js_global,
		'blocks' => $js_blocks,
	),
);

$total_css = count( $css_global ) + count( $css_admin ) + count( $css_blocks );
$total_js  = count( $js_global ) + count( $js_blocks );

// Encode with 2-space indent to match existing convention.
$encoded = json_encode( $manifest, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES );
$encoded = preg_replace_callback(
	'/^( +)/m',
	static function ( array $m ): string {
		return str_repeat( ' ', (int) ( strlen( $m[1] ) / 2 ) );
	},
	(string) $encoded
);
$encoded .= "\n";

$current = (string) file_get_contents( $manifest_fp );

// Sync summary.counts.frontend_css_files / frontend_js_files unconditionally.
$summary_updated = false;
if ( is_readable( $summary_fp ) ) {
	$summary = json_decode( (string) file_get_contents( $summary_fp ), true );
	if ( is_array( $summary ) && isset( $summary['counts'] ) ) {
		$expected = array(
			'frontend_css_files' => $total_css,
			'frontend_js_files'  => $total_js,
		);
		$changed = false;
		foreach ( $expected as $key => $val ) {
			if ( (int) ( $summary['counts'][ $key ] ?? -1 ) !== $val ) {
				$summary['counts'][ $key ] = $val;
				$changed                   = true;
			}
		}
		if ( $changed && ! $dry_run ) {
			$summary_encoded = json_encode( $summary, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES );
			$summary_encoded = preg_replace_callback(
				'/^( +)/m',
				static function ( array $m ): string {
					return str_repeat( ' ', (int) ( strlen( $m[1] ) / 2 ) );
				},
				(string) $summary_encoded
			);
			$summary_encoded .= "\n";
			file_put_contents( $summary_fp, $summary_encoded );
			$summary_updated = true;
		}
	}
}

if ( $encoded === $current ) {
	$msg = "build-frontend-assets: no changes ({$total_css} CSS + {$total_js} JS in sync)";
	if ( $summary_updated ) {
		$msg .= ' [summary.counts re-synced]';
	}
	echo $msg . "\n";
	exit( 0 );
}

if ( $dry_run ) {
	echo "build-frontend-assets: would update manifest.json ({$total_css} CSS + {$total_js} JS)\n";
	exit( 0 );
}

if ( false === file_put_contents( $manifest_fp, $encoded ) ) {
	fwrite( STDERR, "ERROR: failed to write {$manifest_fp}\n" );
	exit( 2 );
}

$msg = "build-frontend-assets: rewrote .frontend_assets ({$total_css} CSS + {$total_js} JS)";
if ( $summary_updated ) {
	$msg .= ' [summary.counts re-synced]';
}
echo $msg . "\n";
exit( 0 );


/**
 * Returns true if the path is a CANONICAL source asset (not a generated
 * variant). Excludes:
 *   - *.min.css / *.min.js (generated by npm run build:min)
 *   - *-rtl.css            (generated by npm run build:rtl)
 *   - build/ or dist/ paths (compiled output)
 *   - node_modules / vendor (deps)
 */
function is_canonical( string $rel_path ): bool {
	if ( str_contains( $rel_path, '/node_modules/' ) ) {
		return false;
	}
	if ( str_contains( $rel_path, '/vendor/' ) ) {
		return false;
	}
	if ( str_starts_with( $rel_path, 'build/' ) || str_starts_with( $rel_path, 'dist/' ) ) {
		return false;
	}
	if ( str_starts_with( $rel_path, 'sdk/dist/' ) || str_starts_with( $rel_path, 'sdk/src/' ) ) {
		return false;
	}
	$base = basename( $rel_path );
	if ( str_ends_with( $base, '.min.css' ) || str_ends_with( $base, '.min.js' ) ) {
		return false;
	}
	if ( str_ends_with( $base, '-rtl.css' ) ) {
		return false;
	}
	return true;
}
